  1	import React, { useState } from 'react';
  2	import {
  3	  Button,
  4	  Dropdown,
  5	  DropdownItem,
  6	  DropdownList,
  7	  MenuToggle,
  8	  MenuToggleCheckbox,
  9	  PaginationProps,
 10	  ToolbarItem
 11	} from '@patternfly/react-core';
 12	import AngleDownIcon from '@patternfly/react-icons/dist/esm/icons/angle-down-icon';
 13	import AngleRightIcon from '@patternfly/react-icons/dist/esm/icons/angle-right-icon';
 14	
 15	export interface ToolbarBulkSelectorProps<T> {
 16	  areAllSelected: boolean;
 17	  areAllExpanded?: boolean;
 18	  onSelectAll?: (flag?: boolean) => void;
 19	  onSelectNone: () => void;
 20	  onExpandAll?: (flag?: boolean) => void;
 21	  selectedRows: T[];
 22	  onSelectMultiple: (items: T[], isSelecting: boolean) => void;
 23	  currentPageItems: T[];
 24	  paginationProps: PaginationProps;
 25	  isExpandable?: boolean;
 26	}
 27	
 28	/**
 29	 * @deprecated this component comes from tackle2-ui legacy code and should probably be moved somewhere else like PF component groups
 30	 */
 31	export const ToolbarBulkSelector = <T,>({
 32	  currentPageItems,
 33	  areAllSelected,
 34	  onSelectAll,
 35	  onSelectNone,
 36	  onExpandAll,
 37	  areAllExpanded,
 38	  selectedRows,
 39	  onSelectMultiple,
 40	  paginationProps,
 41	  isExpandable
 42	}: React.PropsWithChildren<ToolbarBulkSelectorProps<T>>): JSX.Element | null => {
 43	  const [isOpen, setIsOpen] = useState(false);
 44	
 45	  const toggleCollapseAll = (collapse: boolean) => {
 46	    onExpandAll && onExpandAll(!collapse);
 47	  };
 48	  const collapseAllBtn = () => (
 49	    <Button
 50	      variant="control"
 51	      title={`${!areAllExpanded ? 'Expand' : 'Collapse'} all`}
 52	      onClick={() => {
 53	        areAllExpanded !== undefined && toggleCollapseAll(areAllExpanded);
 54	      }}
 55	    >
 56	      {areAllExpanded ? <AngleDownIcon /> : <AngleRightIcon />}
 57	    </Button>
 58	  );
 59	
 60	  const getBulkSelectState = () => {
 61	    let state: boolean | null;
 62	    if (areAllSelected) {
 63	      state = true;
 64	    } else if (selectedRows.length === 0) {
 65	      state = false;
 66	    } else {
 67	      state = null;
 68	    }
 69	    return state;
 70	  };
 71	  const handleSelectAll = (checked: boolean) => {
 72	    onSelectAll?.(!!checked);
 73	  };
 74	
 75	  const selectPage = () =>
 76	    onSelectMultiple(
 77	      currentPageItems.map((item: T) => item),
 78	      true
 79	    );
 80	
 81	  // TODO support i18n / custom text for items below
 82	
 83	  const dropdownItems = [
 84	    <DropdownItem
 85	      onClick={() => {
 86	        handleSelectAll(false);
 87	        setIsOpen(false);
 88	      }}
 89	      data-action="none"
 90	      key="select-none"
 91	      component="button"
 92	    >
 93	      Select none (0 items)
 94	    </DropdownItem>,
 95	    <DropdownItem
 96	      onClick={() => {
 97	        selectPage();
 98	        setIsOpen(false);
 99	      }}
100	      data-action="page"
101	      key="select-page"
102	      component="button"
103	    >
104	      Select page ({currentPageItems.length} items)
105	    </DropdownItem>,
106	    ...(onSelectAll
107	      ? [
108	          <DropdownItem
109	            onClick={() => {
110	              handleSelectAll(true);
111	              setIsOpen(false);
112	            }}
113	            data-action="all"
114	            key="select-all"
115	            component="button"
116	          >
117	            Select all ({paginationProps.itemCount})
118	          </DropdownItem>
119	        ]
120	      : [])
121	  ];
122	
123	  return (
124	    <React.Fragment>
125	      {isExpandable && <ToolbarItem>{collapseAllBtn()}</ToolbarItem>}
126	      <ToolbarItem>
127	        <Dropdown
128	          isOpen={isOpen}
129	          toggle={toggleRef => (
130	            <MenuToggle
131	              ref={toggleRef}
132	              onClick={() => setIsOpen(!isOpen)}
133	              aria-label="Bulk selection menu toggle"
134	              splitButtonOptions={{
135	                items: [
136	                  <MenuToggleCheckbox
137	                    id="bulk-selected-items-checkbox"
138	                    key="bulk-select-checkbox"
139	                    aria-label="Select all"
140	                    onChange={() => {
141	                      if (getBulkSelectState() !== false) {
142	                        onSelectNone();
143	                      } else if (onSelectAll) {
144	                        onSelectAll(true);
145	                      } else {
146	                        selectPage();
147	                      }
148	                    }}
149	                    isChecked={getBulkSelectState()}
150	                  />
151	                ]
152	              }}
153	            />
154	          )}
155	        >
156	          <DropdownList>{dropdownItems}</DropdownList>
157	        </Dropdown>
158	      </ToolbarItem>
159	    </React.Fragment>
160	  );
161	};

